import { useState, useCallback, useEffect } from 'react';
import { BrainCircuit } from 'lucide-react';

/* ============================================================
   HERO VISUAL (Obsidian Holographic HUD)
   A premium, glass-like 3D component enforcing strict Obsidian
   Intelligence parameters (1px teal borders, dark BG, subtle glow).
   ============================================================ */
export default function HeroVisual() {
  const [tilt, setTilt] = useState({ x: 0, y: 0 });
  const [hovering, setHovering] = useState(false);

  const handleMove = useCallback((e) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width - 0.5) * 35; 
    const y = ((e.clientY - rect.top) / rect.height - 0.5) * -35;
    setTilt({ x, y });
  }, []);

  return (
    <div
      onMouseMove={handleMove}
      onMouseEnter={() => setHovering(true)}
      onMouseLeave={() => { setHovering(false); setTilt({ x: 0, y: 0 }); }}
      style={{ 
        position: 'relative', width: '100%', height: 600, 
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        perspective: 1600 
      }}
    >
      <style>{`
        @keyframes spinFlat {
          0% { transform: translate(-50%, -50%) rotate(0deg); }
          100% { transform: translate(-50%, -50%) rotate(360deg); }
        }
        @keyframes scanlineFlash {
          0% { opacity: 0; transform: translateY(-10px); }
          15% { opacity: 1; }
          85% { opacity: 1; }
          100% { opacity: 0; transform: translateY(460px); }
        }
        .core-t {
          transition: all 0.8s cubic-bezier(0.16, 1, 0.3, 1);
        }
      `}</style>

      {/* ΓòÉ THE MOTHERBOARD ΓòÉ */}
      <div className="core-t" style={{
        position: 'absolute', top: '50%', left: '50%',
        width: 560, height: 460, 
        backgroundColor: 'rgba(8, 9, 12, 0.4)', // Slightly transparent var(--bg-primary)
        backdropFilter: 'blur(16px)',
        border: '1px solid var(--teal-12)',
        borderRadius: 'var(--radius-lg)',
        transformStyle: 'preserve-3d',
        transform: `translate(-50%, -50%) rotateX(${tilt.y}deg) rotateY(${tilt.x}deg) rotateZ(${hovering ? 0 : -2}deg)`,
        boxShadow: hovering 
          ? '0 20px 60px rgba(15, 207, 188, 0.08)' 
          : '0 10px 40px rgba(0, 0, 0, 0.5)',
        padding: 'var(--space-3)', 
        display: 'grid', 
        gridTemplateColumns: 'minmax(200px, 1fr) 1.2fr', 
        gridTemplateRows: '1fr 1fr', 
        gap: 'var(--space-3)'
      }}>

        {/* Ambient Grid Background inside Motherboard */}
        <div style={{ position: 'absolute', inset: 0, borderRadius: 'var(--radius-lg)', overflow: 'hidden', zIndex: 1, pointerEvents: 'none' }}>
           {/* Grid Pattern */}
           <div style={{ position: 'absolute', inset: 0, backgroundSize: '30px 30px', backgroundImage: 'linear-gradient(to right, rgba(15, 207, 188, 0.05) 1px, transparent 1px), linear-gradient(to bottom, rgba(15, 207, 188, 0.05) 1px, transparent 1px)', opacity: hovering ? 1 : 0.3, transition: 'opacity 1s ease' }} />

           {/* Animated Glowing Orbs (Data Nodes) */}
           <div style={{ position: 'absolute', top: hovering ? '20%' : '80%', left: '20%', width: 120, height: 120, background: 'var(--teal)', borderRadius: '50%', filter: 'blur(60px)', opacity: hovering ? 0.4 : 0.1, transition: 'all 3s cubic-bezier(0.16, 1, 0.3, 1)' }} />
           <div style={{ position: 'absolute', top: hovering ? '60%' : '10%', right: '10%', width: 150, height: 150, background: 'var(--danger)', borderRadius: '50%', filter: 'blur(70px)', opacity: hovering ? 0.2 : 0.05, transition: 'all 4s cubic-bezier(0.16, 1, 0.3, 1) 0.2s' }} />

           {/* Horizontal Scanner Beam */}
           {hovering && (
             <div style={{ position: 'absolute', left: 0, right: 0, top: 0, height: '100%', background: 'linear-gradient(to bottom, transparent, rgba(15, 207, 188, 0.05) 45%, rgba(15, 207, 188, 0.2) 50%, rgba(15, 207, 188, 0.05) 55%, transparent)', animation: 'scanlineFlash 4s linear infinite' }} />
           )}
        </div>

        {/* ΓÇöΓÇöΓÇö STEP 1: YOUR IDEA (Top Left) ΓÇöΓÇöΓÇö */}
        <div className="obs-card core-t" style={{
           position: 'relative', zIndex: 2,
           gridColumn: '1 / 2', gridRow: '1 / 2',
           backgroundColor: 'var(--bg-elevated)', /* Slate Dark */
           padding: 'var(--space-3)',
           transform: `translateZ(${hovering ? 60 : 20}px) translateX(${hovering ? -10 : 0}px) translateY(${hovering ? -10 : 0}px)`,
           boxShadow: hovering ? '0 12px 30px rgba(0,0,0,0.6)' : 'none',
           display: 'flex', flexDirection: 'column'
        }}>
           <div className="heading-card" style={{ borderBottom: '1px solid var(--teal-12)', paddingBottom: 'var(--space-1)', marginBottom: 'var(--space-2)' }}>Step 1: Your Idea</div>
           <div style={{ flex: 1, display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>
             <p className="text-small" style={{ marginBottom: 'var(--space-1)' }}>Describe your startup:</p>
             <div style={{ padding: 'var(--space-1) var(--space-2)', borderRadius: 'var(--radius-sm)', backgroundColor: 'var(--bg-primary)', border: '1px solid var(--teal-25)', color: 'var(--teal-dim)', fontFamily: 'var(--font-body)', fontWeight: 600, fontSize: 13 }}>
               "AI for Real Estate"
             </div>
           </div>
        </div>

        {/* ΓÇöΓÇöΓÇö STEP 2: ARIA BRAIN (Bottom Left) ΓÇöΓÇöΓÇö */}
        <div className="obs-card core-t" style={{
           position: 'relative', zIndex: 2,
           gridColumn: '1 / 2', gridRow: '2 / 3',
           backgroundColor: 'var(--bg-secondary)', 
           border: hovering ? '1px solid rgba(255, 77, 77, 0.4)' : '1px solid var(--teal-12)', /* Danger hint */
           padding: 'var(--space-3)',
           transform: `translateZ(${hovering ? 100 : 30}px) translateX(${hovering ? -15 : 0}px) translateY(${hovering ? 10 : 0}px)`,
           boxShadow: hovering ? '0 16px 40px rgba(255, 77, 77, 0.08)' : '0 10px 20px rgba(0,0,0,0.4)',
           display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center'
        }}>
           <div className="text-label" style={{ borderBottom: '1px solid var(--teal-12)', paddingBottom: 'var(--space-1)', marginBottom: 'var(--space-3)', width: '100%', textAlign: 'center', fontSize: 11, color: hovering ? 'var(--danger)' : 'var(--teal)' }}>Step 2: ARIA Brain</div>

           <div style={{ position: 'relative', width: 64, height: 64, marginBottom: 'var(--space-3)' }}>
              <div style={{ position: 'absolute', top: '50%', left: '50%', width: 80, height: 80, border: hovering ? '1px dashed var(--danger)' : '1px dashed var(--teal-40)', borderRadius: '50%', animation: `spinFlat ${hovering ? '4s' : '15s'} linear infinite`, transition: 'all 0.8s' }} />
              <div style={{ position: 'absolute', top: '50%', left: '50%', width: 64, height: 64, border: hovering ? '1px solid rgba(255, 77, 77, 0.4)' : '1px solid var(--teal-25)', borderRadius: '50%', animation: `spinFlat ${hovering ? '3s' : '10s'} reverse linear infinite`, transition: 'all 0.8s' }} />
              <div style={{ width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', color: hovering ? 'var(--danger)' : 'var(--teal)', transition: 'color 0.8s' }}>
                 <BrainCircuit size={24} strokeWidth={1.5} />
              </div>
           </div>

           <div className="text-small" style={{ color: hovering ? 'var(--danger)' : 'var(--text-muted)' }}>
             {hovering ? '> Analyzing market...' : 'Waiting for idea'}
           </div>
        </div>

        {/* ΓÇöΓÇöΓÇö STEP 3: FINAL REPORT (Right Column) ΓÇöΓÇöΓÇö */}
        <div className="obs-card core-t" style={{
           position: 'relative', zIndex: 2, overflow: 'hidden',
           gridColumn: '2 / 3', gridRow: '1 / span 2',
           backgroundColor: 'var(--bg-elevated)',
           padding: 'var(--space-3)',
           transform: `translateZ(${hovering ? 80 : 10}px) translateX(${hovering ? 15 : 0}px)`,
           boxShadow: hovering ? '0 12px 40px rgba(0,0,0,0.5)' : 'none',
           display: 'flex', flexDirection: 'column'
        }}>
           {/* Subtle corner glow */}
           <div style={{ position: 'absolute', top: -30, right: -30, width: 120, height: 120, background: 'var(--teal-06)', borderRadius: '50%', filter: 'blur(40px)', opacity: hovering ? 1 : 0, transition: 'opacity 0.8s', pointerEvents: 'none' }} />

           <div className="heading-card" style={{ borderBottom: '1px solid var(--teal-12)', paddingBottom: 'var(--space-1)', marginBottom: 8 }}>Step 3: Your Report</div>

           {/* Score + Summary Row */}
           <div style={{ display: 'flex', gap: 12, marginBottom: 10 }}>
             {/* Viability Score Ring */}
             <div style={{ position: 'relative', width: 52, height: 52, flexShrink: 0 }}>
               <svg viewBox="0 0 52 52" style={{ width: 52, height: 52, transform: 'rotate(-90deg)' }}>
                 <circle cx="26" cy="26" r="22" fill="none" stroke="var(--teal-12)" strokeWidth="3" />
                 <circle cx="26" cy="26" r="22" fill="none" stroke="var(--teal)" strokeWidth="3"
                   strokeDasharray={`${hovering ? 110 : 20} 138`}
                   strokeLinecap="round"
                   style={{ transition: 'stroke-dasharray 1.2s cubic-bezier(0.16, 1, 0.3, 1)' }} />
               </svg>
               <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', fontFamily: 'var(--font-mono)', fontSize: 13, fontWeight: 700, color: hovering ? 'var(--teal)' : 'var(--text-muted)', transition: 'color 0.6s' }}>
                 {hovering ? '82' : '--'}
               </div>
             </div>
             <div style={{ display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>
               <div style={{ fontFamily: 'var(--font-mono)', fontSize: 9, textTransform: 'uppercase', letterSpacing: 1.5, color: 'var(--teal-40)', marginBottom: 2 }}>Viability Score</div>
               <div style={{ fontSize: 11, color: hovering ? 'var(--teal)' : 'var(--text-muted)', fontWeight: 600, transition: 'color 0.6s' }}>{hovering ? 'High Potential' : 'Pending...'}</div>
             </div>
           </div>

           {/* Inner Report Panel */}
           <div style={{ flex: 1, backgroundColor: 'var(--bg-primary)', borderRadius: 'var(--radius-md)', border: '1px solid var(--teal-12)', padding: '10px', display: 'flex', flexDirection: 'column', gap: 8 }}>

              {/* Stat Rows */}
              {[
                { label: 'Market Size', value: '$4.2B', pct: 85 },
                { label: 'Competition', value: 'Medium', pct: 55 },
                { label: 'Growth Rate', value: '24%', pct: 72 },
              ].map((stat, i) => (
                <div key={stat.label}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 3 }}>
                    <span style={{ fontFamily: 'var(--font-mono)', fontSize: 9, textTransform: 'uppercase', letterSpacing: 1, color: 'var(--text-muted)' }}>{stat.label}</span>
                    <span style={{ fontFamily: 'var(--font-mono)', fontSize: 9, color: hovering ? 'var(--teal)' : 'var(--teal-40)', fontWeight: 600, transition: 'color 0.6s' }}>{hovering ? stat.value : '---'}</span>
                  </div>
                  <div style={{ height: 3, backgroundColor: 'var(--teal-12)', borderRadius: 2, overflow: 'hidden' }}>
                    <div style={{ height: '100%', width: hovering ? `${stat.pct}%` : '0%', backgroundColor: i === 1 ? 'var(--danger)' : 'var(--teal)', borderRadius: 2, transition: `width 1s cubic-bezier(0.16, 1, 0.3, 1) ${i * 0.15}s` }} />
                  </div>
                </div>
              ))}

              {/* Tags */}
              <div style={{ display: 'flex', gap: 4, flexWrap: 'wrap', marginTop: 2 }}>
                {['PropTech', 'B2B SaaS', 'AI/ML'].map((tag, i) => (
                  <span key={tag} style={{
                    padding: '2px 8px', borderRadius: 100, fontSize: 8, fontFamily: 'var(--font-mono)', textTransform: 'uppercase', letterSpacing: 1,
                    background: hovering ? (i === 0 ? 'var(--teal-12)' : i === 1 ? 'rgba(255,77,77,0.1)' : 'rgba(255,190,0,0.1)') : 'rgba(255,255,255,0.03)',
                    color: hovering ? (i === 0 ? 'var(--teal)' : i === 1 ? 'var(--danger)' : '#FFB800') : 'var(--text-muted)',
                    border: `1px solid ${hovering ? (i === 0 ? 'var(--teal-25)' : i === 1 ? 'rgba(255,77,77,0.2)' : 'rgba(255,190,0,0.2)') : 'var(--teal-12)'}`,
                    transition: `all 0.6s ease ${0.3 + i * 0.1}s`,
                    opacity: hovering ? 1 : 0.4
                  }}>{tag}</span>
                ))}
              </div>

              {/* Mini Bar Chart */}
              <div style={{ marginTop: 'auto', display: 'flex', alignItems: 'flex-end', height: 48, gap: 3 }}>
                {[65, 40, 85, 55, 70, 90, 45, 75, 60].map((h, i) => (
                  <div key={i} style={{
                    flex: 1,
                    backgroundColor: i % 3 === 2 ? 'var(--danger)' : 'var(--teal)',
                    opacity: hovering ? (0.5 + (h / 200)) : 0.1,
                    height: hovering ? `${h}%` : '12%',
                    borderRadius: '2px 2px 0 0',
                    transition: `all 0.8s cubic-bezier(0.16, 1, 0.3, 1) ${i * 0.05}s`
                  }} />
                ))}
              </div>
           </div>
        </div>

      </div>
    </div>
  );
}

import { useState, useCallback, useEffect } from 'react';
import { Compass, Target, Users } from 'lucide-react';

export default function IntelligenceCore() {
  const [tilt, setTilt] = useState({ x: 0, y: 0 });

  const handleMove = useCallback((e) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width - 0.5) * 60; 
    const y = ((e.clientY - rect.top) / rect.height - 0.5) * -60;
    setTilt({ x, y });
  }, []);

  return (
    <div onMouseMove={handleMove} onMouseLeave={() => setTilt({ x: 0, y: 0 })}
         style={{ width: '100%', height: 600, display: 'flex', alignItems: 'center', justifyContent: 'center', perspective: 2000 }}>

       <style>{`
          @keyframes floatData1 { 0%, 100% { transform: translateZ(50px) translateY(0) rotateY(15deg); } 50% { transform: translateZ(60px) translateY(-15px) rotateY(10deg); } }
          @keyframes floatData2 { 0%, 100% { transform: translateZ(80px) translateY(0) rotateY(-20deg); } 50% { transform: translateZ(90px) translateY(-20px) rotateY(-15deg); } }
          @keyframes floatData3 { 0%, 100% { transform: translateZ(120px) translateY(0) rotateX(15deg); } 50% { transform: translateZ(130px) translateY(-10px) rotateX(25deg); } }
          @keyframes orbitBrain { 0% { transform: rotateY(0deg) rotateZ(0deg); } 100% { transform: rotateY(360deg) rotateZ(360deg); } }
          @keyframes pulseMesh { 0%, 100% { opacity: 0.3; transform: scale(1); } 50% { opacity: 0.8; transform: scale(1.05); } }
       `}</style>

       {/* Main 3D Container tracking mouse */}
       <div style={{
         position: 'relative', width: 400, height: 400,
         transformStyle: 'preserve-3d',
         transform: `rotateX(${tilt.y}deg) rotateY(${tilt.x}deg)`,
         transition: 'transform 0.6s cubic-bezier(0.16, 1, 0.3, 1)'
       }}>

          {/* ARIA Artificial Brain Core */}
          <div style={{
             position: 'absolute', top: '50%', left: '50%',
             width: 160, height: 160, marginLeft: -80, marginTop: -80,
             transformStyle: 'preserve-3d',
             animation: 'orbitBrain 24s linear infinite'
          }}>
             {/* Glowing Engine Orb */}
             <div style={{ position: 'absolute', inset: -20, borderRadius: '50%', background: 'radial-gradient(circle, var(--teal) 0%, transparent 60%)', filter: 'blur(30px)', opacity: 0.5, animation: 'pulseMesh 4s ease-in-out infinite' }} />

             {/* 3D Wireframe globe / neural node */}
             {Array.from({ length: 4 }).map((_, i) => (
               <div key={`y${i}`} style={{
                 position: 'absolute', inset: 0, borderRadius: '50%',
                 border: '1px solid var(--teal-12)',
                 transform: `rotateY(${i * 45}deg)`,
               }} />
             ))}
             {Array.from({ length: 4 }).map((_, i) => (
               <div key={`x${i}`} style={{
                 position: 'absolute', inset: 0, borderRadius: '50%',
                 border: '1px dashed var(--teal-25)',
                 transform: `rotateX(90deg) rotateY(${i * 45}deg)`,
               }} />
             ))}

             {/* Central Processing Singularity */}
             <div style={{ position: 'absolute', top: '50%', left: '50%', width: 32, height: 32, marginLeft: -16, marginTop: -16, backgroundColor: 'var(--teal)', borderRadius: '50%', boxShadow: '0 0 50px var(--teal)', animation: 'pulseMesh 2s infinite' }} />
          </div>

          {/* ΓòÉΓòÉΓòÉΓòÉ 3D FLOATING DATA CARDS EXTRACTED BY THE AI ΓòÉΓòÉΓòÉΓòÉ */}

          {/* Card 1: Market Intelligence (Top Left) */}
          <div style={{
             position: 'absolute', top: 20, left: -100,
             width: 200, padding: 20, borderRadius: 12,
             backgroundColor: 'rgba(14, 17, 23, 0.6)', backdropFilter: 'blur(16px)',
             border: '1px solid var(--teal-25)',
             boxShadow: '0 30px 60px rgba(0,0,0,0.8), inset 0 0 20px rgba(15, 207, 188, 0.15)',
             animation: 'floatData1 6s ease-in-out infinite',
             transformStyle: 'preserve-3d', zIndex: 10
          }}>
             <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 16 }}>
                <Compass size={18} color="var(--teal)" />
                <span style={{ fontSize: 12, fontWeight: 700, color: 'var(--teal)', letterSpacing: 1.5 }}>MARKET NAV</span>
             </div>
             <div style={{ fontSize: 32, fontFamily: 'Playfair Display', color: 'var(--text-primary)', marginBottom: 12, lineHeight: 1 }}>$4.2B</div>
             {/* Mini Live Chart */}
             <div style={{ display: 'flex', gap: 6, alignItems: 'flex-end', height: 48 }}>
                <div style={{ width: '25%', height: '40%', backgroundColor: 'var(--teal-25)', borderRadius: 2 }} />
                <div style={{ width: '25%', height: '55%', backgroundColor: 'var(--teal-40)', borderRadius: 2 }} />
                <div style={{ width: '25%', height: '75%', backgroundColor: 'var(--teal)', borderRadius: 2 }} />
                <div style={{ width: '25%', height: '100%', backgroundColor: 'var(--teal)', borderRadius: 2, boxShadow: '0 0 16px var(--teal)' }} />
             </div>
          </div>

          {/* Card 2: Competitor Matrix (Bottom Left) */}
          <div style={{
             position: 'absolute', bottom: 20, left: -60,
             width: 200, padding: 20, borderRadius: 12,
             backgroundColor: 'rgba(14, 17, 23, 0.6)', backdropFilter: 'blur(16px)',
             border: '1px solid var(--danger)',
             boxShadow: '0 30px 60px rgba(0,0,0,0.8), inset 0 0 30px rgba(255, 77, 77, 0.15)',
             animation: 'floatData2 8s ease-in-out infinite', animationDelay: '1s',
             transformStyle: 'preserve-3d', zIndex: 15
          }}>
             <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 16 }}>
                <Target size={18} color="var(--danger)" />
                <span style={{ fontSize: 12, fontWeight: 700, color: 'var(--danger)', letterSpacing: 1.5 }}>RIVAL NODE</span>
             </div>
             {/* Matrix Grid revealing competitor weakness */}
             <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: 8 }}>
                <div style={{ height: 32, border: '1px solid var(--danger)', borderRadius: 6, backgroundColor: 'var(--danger-10)' }} />
                <div style={{ height: 32, border: '1px solid var(--danger)', borderRadius: 6, backgroundColor: 'var(--danger-10)' }} />
                <div style={{ height: 32, border: '1px solid var(--teal)', borderRadius: 6, backgroundColor: 'var(--teal-12)', boxShadow: '0 0 20px var(--teal)' }} />
                <div style={{ height: 32, border: '1px solid var(--danger)', borderRadius: 6, backgroundColor: 'var(--danger-10)' }} />
             </div>
          </div>

          {/* Card 3: Audience Demographics (Right Center) */}
          <div style={{
             position: 'absolute', top: 100, right: -120,
             width: 240, padding: 20, borderRadius: 12,
             backgroundColor: 'rgba(14, 17, 23, 0.6)', backdropFilter: 'blur(16px)',
             border: '1px solid var(--teal-40)',
             boxShadow: '0 30px 60px rgba(0,0,0,0.8), inset 0 0 20px rgba(15, 207, 188, 0.05)',
             animation: 'floatData3 7s ease-in-out infinite', animationDelay: '2s',
             transformStyle: 'preserve-3d', zIndex: 20, overflow: 'hidden'
          }}>
             {/* Scanning Line overlay */}
             <div style={{ position: 'absolute', width: '100%', height: 2, backgroundColor: 'var(--teal)', left: 0, top: '50%', boxShadow: '0 0 20px var(--teal)', opacity: 0.5 }} />

             <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 16 }}>
                <Users size={18} color="var(--teal)" />
                <span style={{ fontSize: 12, fontWeight: 700, color: 'var(--text-secondary)', letterSpacing: 1.5 }}>AUDIENCE DEMO</span>
             </div>
             <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                   <div style={{ width: 28, height: 28, borderRadius: '50%', border: '2px solid var(--teal)' }} />
                   <div style={{ flex: 1, margin: '0 12px', height: 6, backgroundColor: 'var(--teal-12)', borderRadius: 3 }}><div style={{ width: '85%', height: '100%', backgroundColor: 'var(--teal)', borderRadius: 3, boxShadow: '0 0 10px var(--teal)' }} /></div>
                   <div style={{ fontSize: 14, color: 'var(--text-primary)', fontWeight: 600 }}>85%</div>
                </div>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                   <div style={{ width: 28, height: 28, borderRadius: '50%', border: '2px dotted var(--teal)' }} />
                   <div style={{ flex: 1, margin: '0 12px', height: 6, backgroundColor: 'var(--teal-12)', borderRadius: 3 }}><div style={{ width: '40%', height: '100%', backgroundColor: 'var(--teal-40)', borderRadius: 3 }} /></div>
                   <div style={{ fontSize: 14, color: 'var(--text-primary)' }}>40%</div>
                </div>
             </div>
          </div>

          {/* Holographic Input Text (Represents the user Prompt feeding the AI Engine) */}
          <div style={{
             position: 'absolute', bottom: -100, left: '50%', marginLeft: -160,
             width: 320, textAlign: 'center',
             transform: 'translateZ(100px)',
             color: 'var(--teal)', fontFamily: 'Outfit', fontSize: 16, letterSpacing: 1,
             textShadow: '0 0 15px var(--teal)', opacity: 0.9
          }}>
             &gt; Searching live market endpoints...
             <div style={{ height: 1, width: '100%', backgroundColor: 'var(--teal-40)', marginTop: 12, boxShadow: '0 0 10px var(--teal)' }} />
          </div>

       </div>
    </div>
  );
}

import { useState, useCallback, useEffect } from 'react';

export default function ProcessOrb() {
  const [tilt, setTilt] = useState({ x: 0, y: 0 });
  const [hovering, setHovering] = useState(false);

  const handleMove = useCallback((e) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width - 0.5) * 140; // Intense rotation control
    const y = ((e.clientY - rect.top) / rect.height - 0.5) * -140;
    setTilt({ x, y });
  }, []);

  // 14 concentric aperture rings
  const rings = Array.from({ length: 14 }).map((_, i) => {
    const size = 320 - (i * 20); // Down to 60px
    const isPrimary = i % 4 === 0;
    const isSecondary = i % 3 === 0;

    // Telescopes heavily on hover
    const zOffset = hovering ? (200 - (i * 30)) : 0;
    const dir = i % 2 === 0 ? 1 : -1;
    const duration = 15 + (i * 2);

    return (
      <div key={i} style={{
        position: 'absolute', top: '50%', left: '50%',
        width: size, height: size,
        marginLeft: -(size/2), marginTop: -(size/2),
        transformStyle: 'preserve-3d',
        transform: `translateZ(${zOffset}px) rotateZ(${hovering ? (i * 20) : 0}deg)`,
        transition: 'transform 1.2s cubic-bezier(0.16, 1, 0.3, 1)',
      }}>
         {/* Inner Ring handles the infinite rotation */}
         <div style={{
           width: '100%', height: '100%', borderRadius: '50%', position: 'relative',
           border: isPrimary ? '1px solid var(--teal)' : isSecondary ? '1px dashed var(--danger)' : '1px solid var(--teal-25)',
           boxShadow: (hovering && isPrimary) ? 'inset 0 0 30px rgba(15, 207, 188, 0.4), 0 0 30px rgba(15, 207, 188, 0.4)' : 'none',
           animation: `spinRing ${duration}s linear infinite ${dir > 0 ? 'normal' : 'reverse'}`,
           transition: 'box-shadow 1s'
         }}>
             {/* Data Nodes attached directly to ring edge */}
             {isPrimary && <div style={{ width: 8, height: 8, backgroundColor: 'var(--teal)', borderRadius: '50%', position: 'absolute', top: -4, left: '50%', marginLeft: -4, boxShadow: '0 0 15px var(--teal)' }} />}
             {isSecondary && <div style={{ width: 4, height: 16, backgroundColor: 'var(--danger)', position: 'absolute', bottom: -8, left: '50%', marginLeft: -2, boxShadow: '0 0 15px var(--danger)' }} />}
         </div>
      </div>
    );
  });

  return (
    <div onMouseMove={handleMove} 
         onMouseEnter={() => setHovering(true)}
         onMouseLeave={() => { setHovering(false); setTilt({ x: 0, y: 0 }); }}
         style={{ width: '100%', height: 440, display: 'flex', alignItems: 'center', justifyContent: 'center', perspective: 1800, cursor: 'crosshair' }}>

       <style>{`
          @keyframes spinRing { 100% { transform: rotate(360deg); } }
          @keyframes spinAperture { 100% { transform: rotate(360deg); } }
          @keyframes pulseCore {
             0%, 100% { transform: translate(-50%, -50%) scale(1); box-shadow: 0 0 60px var(--teal), inset 0 0 30px var(--teal); }
             50% { transform: translate(-50%, -50%) scale(1.1); box-shadow: 0 0 100px var(--teal), inset 0 0 50px #fff; }
          }
       `}</style>

       <div style={{
         position: 'relative', width: 320, height: 320,
         transformStyle: 'preserve-3d',
         transform: `rotateX(${tilt.y}deg) rotateY(${tilt.x}deg)`,
         transition: 'transform 0.2s ease-out'
       }}>

          {rings}

          {/* Core Singularity */}
          <div style={{
            position: 'absolute', left: '50%', top: '50%', zIndex: 10,
            width: 40, height: 40, borderRadius: '50%',
            backgroundColor: 'var(--bg-primary)', border: '2px solid var(--teal)',
            transform: `translate(-50%, -50%) translateZ(${hovering ? -220 : 0}px)`,
            transition: 'transform 1.2s cubic-bezier(0.16, 1, 0.3, 1)',
            animation: hovering ? 'pulseCore 1.5s ease-in-out infinite' : 'none'
          }}>
             <div style={{ position: 'absolute', inset: 6, backgroundColor: 'var(--teal)', borderRadius: '50%', filter: 'blur(4px)' }} />
          </div>

          {/* Frame Reticle */}
          <div style={{
            position: 'absolute', inset: -30, borderRadius: '50%',
            borderTop: '2px solid var(--danger)', borderBottom: '2px dashed var(--teal)',
            borderLeft: '2px solid transparent', borderRight: '2px solid transparent',
            animation: 'spinAperture 10s linear infinite', opacity: hovering ? 1 : 0.3, transition: 'opacity 1s'
          }} />

          {/* Deep Z-axis Laser Beam */}
          <div style={{
             position: 'absolute', left: '50%', top: '50%',
             width: 4, height: 800, marginLeft: -2, marginTop: -400,
             background: 'linear-gradient(to bottom, transparent, var(--danger) 50%, transparent)',
             transform: 'rotateX(90deg)',
             opacity: hovering ? 0.9 : 0, filter: 'blur(3px)',
             transition: 'opacity 0.6s', pointerEvents: 'none'
          }} />

       </div>
    </div>
  );
}
